WHERE id = #{id}
  AND user_id = #{userId}
  AND status = 'PENDING'
  AND deleted = 0

mapper.select:
SELECT * FROM supply_claim_order
WHERE user_id = #{userId}
  AND deleted = 0

    AND status = #{status}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM supply_claim_order
WHERE user_id = #{userId}
  AND deleted = 0

    AND status = #{status}

SELECT * FROM supply_claim_order
WHERE user_id = #{userId}
  AND deleted = 0
  AND created_at >= #{from}
  AND created_at < #{toExclusive}
ORDER BY created_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM supply_claim_order
WHERE user_id = #{userId}
  AND deleted = 0
  AND created_at >= #{from}
  AND created_at < #{toExclusive}

